B.Dx=s(["assets/images/rozemoon/rozemoon_fg.png","assets/images/rozemoon/rozemoon_fg1.png","assets/images/rozemoon/rozemoon_fg2.png","assets/images/rozemoon/rozemoon_fg3.png"],t.s)
B.HD=new A.hV("Roze Moon","\ud83c\udf38 Welcome to Roze Moon \u2013 Your Gateway to Beautiful Flowers! \ud83c\udf38\nDiscover a world of floral elegance with Roze Moon, your ultimate destination for ordering fresh flowers effortlessly. Whether it's a special occasion or just a gesture to brighten someone's day, we've got you covered with stunning bouquets, tailored arrangements, and seamless ordering options.","https://play.google.com/store/apps/details?id=com.rozemoon.app","https://apps.apple.com/eg/app/roze-moon/id6739536345",null,"Developed at Tuwaiq \u2013 E-commerce Application",B.BV,null,"2025","Live - Ongoing",B.Dx)
